// Parse JSON output from dashboard script
const items = $input.all();
const jsonOutput = items[0].json.stdout || items[0].json.stderr || items[0].json;

let dashboardData;
try {
  // Try to parse as JSON string first
  if (typeof jsonOutput === 'string') {
    dashboardData = JSON.parse(jsonOutput);
  } else {
    dashboardData = jsonOutput;
  }
} catch (e) {
  throw new Error(`Failed to parse dashboard JSON: ${e.message}. Output: ${jsonOutput}`);
}

// Extract health status
const systemHealthy = dashboardData.system?.healthy ?? false;
const foksOk = dashboardData.services?.foks?.health?.ok ?? false;
const lmstudioOk = dashboardData.services?.lmstudio?.health?.ok ?? false;
const fbpOk = dashboardData.services?.fbp?.health?.ok ?? false;
const fbpOnDemand = dashboardData.services?.fbp?.health?.on_demand ?? true;

// Build status messages
const foksStatus = foksOk ? '✅ Running' : '❌ Down';
const lmstudioStatus = lmstudioOk ? '✅ Running' : '❌ Down';
let fbpStatus;
if (fbpOnDemand && !fbpOk) {
  fbpStatus = '⚪ On-demand (not running)';
} else if (fbpOk) {
  fbpStatus = '✅ Running';
} else {
  fbpStatus = '❌ Down';
}

// Determine which required service is down (if any)
let requiredServiceDown = null;
if (!foksOk) {
  requiredServiceDown = 'FoKS Backend';
} else if (!lmstudioOk) {
  requiredServiceDown = 'LM Studio';
}

// Build notification content
let title, message;

if (systemHealthy) {
  title = 'Good morning – M3 Status';
  message = `FoKS: ${foksStatus}\nLM Studio: ${lmstudioStatus}\nFBP: ${fbpStatus}`;
} else {
  title = '⚠️ Morning Brain – Attention Needed';
  message = `${requiredServiceDown || 'Unknown service'} is down.\n\nFoKS: ${foksStatus}\nLM Studio: ${lmstudioStatus}\nFBP: ${fbpStatus}`;
}

// Escape quotes for shell command safety
const escapeForShell = (str) => str.replace(/"/g, '\\"').replace(/\$/g, '\\$');
const titleEscaped = escapeForShell(title);
const messageEscaped = escapeForShell(message);

return [{
  json: {
    systemHealthy,
    foksOk,
    lmstudioOk,
    fbpOk,
    fbpOnDemand,
    requiredServiceDown,
    title,
    message,
    titleEscaped,
    messageEscaped,
    timestamp: dashboardData.timestamp,
    rawData: dashboardData
  }
}];
